import{_ as e,o as t,c as a,O as i}from"./chunks/framework.bdcb0ee1.js";const f=JSON.parse('{"title":"Topic Templates","description":"","frontmatter":{},"headers":[],"relativePath":"administration/config/topic-templates.md","filePath":"administration/config/topic-templates.md","lastUpdated":1773166741000}'),o={name:"administration/config/topic-templates.md"},l=i('<h1 id="topic-templates" tabindex="-1">Topic Templates <a class="header-anchor" href="#topic-templates" aria-label="Permalink to &quot;Topic Templates&quot;">​</a></h1><p>Topic templates allow you to prefill the topic creation form in a specific forum with structured content. This is especially useful for:</p><ul><li>Support forms (e.g. “Please describe your issue…”)</li><li>Bug reports</li><li>Feature requests</li><li>Application templates</li></ul><p>You can manage templates from the <strong>Board Config</strong> section in the Admin Control Panel.</p><h2 id="creating-a-template" tabindex="-1">Creating a Template <a class="header-anchor" href="#creating-a-template" aria-label="Permalink to &quot;Creating a Template&quot;">​</a></h2><p>To create a new template:</p><ul><li><strong>Name</strong>: A label to identify the template in the admin area.</li><li><strong>Content</strong>: The prefilled content that will appear in the topic body when users create a new thread. This field supports BBCode.</li></ul><img width="1943" height="617" alt="image" src="https://github.com/user-attachments/assets/1d526fb6-cb5c-4b35-b3ee-6134311f58dc"><h2 id="applying-a-template-to-a-forum" tabindex="-1">Applying a Template to a Forum <a class="header-anchor" href="#applying-a-template-to-a-forum" aria-label="Permalink to &quot;Applying a Template to a Forum&quot;">​</a></h2><p>Once created, templates are not active until assigned.</p><p>To use a template in a forum:</p><ol><li>Go to <strong>Section Management</strong>.</li><li>Edit the forum where you want to apply the template.</li><li>Select the desired topic template from the <strong>Template</strong> dropdown.</li></ol><p>The selected template will now automatically populate the topic body for all new threads in that forum.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Only one template can be applied per forum.</li><li>Templates can be edited at any time.</li><li>Changing the template does not affect existing topics.</li></ul>',15),n=[l];function r(p,s,c,m,d,h){return t(),a("div",null,n)}const g=e(o,[["render",r]]);export{f as __pageData,g as default};
